 23 /// Return true if it's possible to assume IEEE treatment of input denormals in
 24 /// \p F for \p Val.
 25 static bool inputDenormalIsIEEE(DenormalMode Mode) {
 26   return Mode.Input == DenormalMode::IEEE;
 27 }
 28 
 29 static bool inputDenormalIsIEEEOrPosZero(DenormalMode Mode) {
 30   return Mode.Input == DenormalMode::IEEE ||
 31          Mode.Input == DenormalMode::PositiveZero;
 32 }
 33 
 34 bool KnownFPClass::isKnownNeverLogicalZero(DenormalMode Mode) const {
 35   return isKnownNeverZero() &&
 36          (isKnownNeverSubnormal() || inputDenormalIsIEEE(Mode));
 37 }
 38 
 39 bool KnownFPClass::isKnownNeverLogicalNegZero(DenormalMode Mode) const {
 40   return isKnownNeverNegZero() &&
 41          (isKnownNeverNegSubnormal() || inputDenormalIsIEEEOrPosZero(Mode));
 42 }
